Greedy insertion using normalized cost increase per unit distance plus penalty for exceeding load capacity, preferring closer station pairs within tighter time windows, while ensuring every order is assigned either to the best feasible existing route or a new assign slot.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	currentAssignCount := dispatch.AssignsLen
	if currentAssignCount > MAXASSIGNS {
		currentAssignCount = MAXASSIGNS
	}

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		shipID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		baseDist := cal_dis(ori, des)
		timeWindowPenalty := 0.0
		if ori.TimeEnd > 0 && des.TimeStart > 0 {
			timeGap := float64(des.TimeStart - ori.TimeEnd)
			if timeGap < 0 {
				timeWindowPenalty = -timeGap * 0.5
			}
		}
		normalizationFactor := baseDist + timeWindowPenalty + 1.0

		bestAssignIdx := -1
		bestScore := 1e308
		originalCosts := make([]float64, currentAssignCount)

		for i := 0; i < currentAssignCount; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
			assignLoad := 0
			for _, s := range dispatch.Assigns[i].Stations {
				assignLoad += s.Load
			}
			loadPenalty := 0.0
			if assignLoad+ori.Load+dess[orderIdx].Load > 100 {
				loadPenalty = 10000.0
			}
			success := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				costDelta := newCost - originalCosts[i]
				score := (costDelta + loadPenalty*0.1) / normalizationFactor
				if score < bestScore && newCost >= 0 {
					bestScore = score
					bestAssignIdx = i
				}
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		if currentAssignCount < MAXASSIGNS {
			i := currentAssignCount
			success := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					score := newCost / normalizationFactor
					if bestAssignIdx == -1 || score < bestScore {
						bestScore = score
						bestAssignIdx = i
					}
				}
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			if bestAssignIdx >= currentAssignCount {
				dispatch.AssignsLen = bestAssignIdx + 1
				currentAssignCount = dispatch.AssignsLen
			}
		} else {
			fallbackIdx := currentAssignCount
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen = fallbackIdx + 1
				currentAssignCount = dispatch.AssignsLen
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

