population.algorithm:
Greedy insertion with cheapest feasible assign selection per order using full trial-and-error search across all assigns including empty ones, falling back to creating a new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	currentAssignCount := dispatch.AssignsLen
	if currentAssignCount > MAXASSIGNS {
		currentAssignCount = MAXASSIGNS
	}

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		shipID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		bestAssignIdx := -1
		bestCostDelta := 1e308
		originalCosts := make([]float64, currentAssignCount)

		// Trial insertion into every existing assign
		for i := 0; i < currentAssignCount; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
			success := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				costDelta := newCost - originalCosts[i]
				if costDelta < bestCostDelta && newCost >= 0 {
					bestCostDelta = costDelta
					bestAssignIdx = i
				}
			}
			// Rollback trial
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		// Also try inserting into a brand‑new empty assign if there is room
		if bestAssignIdx == -1 || currentAssignCount < MAXASSIGNS {
			i := currentAssignCount
			if i < MAXASSIGNS {
				// Save original empty state (no ships yet)
				success := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[i].GenRoute()
					newCost := dispatch.Assigns[i].Cost
					if newCost >= 0 {
						// New assign cost replaces infinite baseline
						costDelta := newCost - 0.0
						if bestAssignIdx == -1 || costDelta < bestCostDelta {
							bestCostDelta = costDelta
							bestAssignIdx = i
						}
					}
				}
				// Always rollback trial for potential new slot
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
		}

		// Commit the best insertion found
		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			if bestAssignIdx >= currentAssignCount {
				dispatch.AssignsLen = bestAssignIdx + 1
				currentAssignCount = dispatch.AssignsLen
			}
		} else {
			// Fallback: force into a new assign even if time windows seem tight,
			// because the problem guarantees feasibility via seed insertion rules.
			fallbackIdx := currentAssignCount
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen = fallbackIdx + 1
				currentAssignCount = dispatch.AssignsLen
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

