population.algorithm:
Greedy regret-based insertion evaluating multiple candidate positions per assign with load-aware feasibility checks and deterministic fallback creation when no feasible insertion exists among existing assigns.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for shipOffset := 0; shipOffset < orderCount; shipOffset++ {
		oriSt := oris[shipOffset]
		desSt := dess[shipOffset]
		orderID := total_ship + shipOffset
		orderLoad := oriSt.Load + desSt.Load
		type candidate struct {
			idx       int
			delta     float64
			regret    float64
			secondBest float64
		}
		var candidates []candidate
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			originalCost := assign.Cost
			bestDelta := INF_COST
			secondDelta := INF_COST
			feasibleFound := false
			if assign.AddShip(orderID, oriSt, desSt) {
				assign.GenRoute()
				if assign.Cost >= 0 {
					feasibleFound = true
					bestDelta = assign.Cost - originalCost
				}
				assign.RemoveShip(orderID)
				assign.GenRoute()
			}
			if feasibleFound {
				for j := 0; j < dispatch.AssignsLen; j++ {
					if j == i {
						continue
					}
					other := &dispatch.Assigns[j]
					oc := other.Cost
					if other.AddShip(orderID, oriSt, desSt) {
						other.GenRoute()
						if other.Cost >= 0 {
							curDelta := other.Cost - oc
							if curDelta < secondDelta {
								secondDelta = curDelta
							}
						}
						other.RemoveShip(orderID)
						other.GenRoute()
					}
				}
				if secondDelta >= INF_COST {
					secondDelta = bestDelta * 2
				}
				regretVal := secondDelta - bestDelta
				candidates = append(candidates, candidate{i, bestDelta, regretVal, secondDelta})
			}
		}
		inserted := false
		if len(candidates) > 0 {
			chosen := 0
			maxRegret := -INF_COST
			for k, c := range candidates {
				composite := c.delta - 0.3*c.regret
				if composite < 0 {
					composite = c.delta
				}
				effectiveScore := composite*(1.0+float64(orderLoad)*0.005)
				if effectiveScore < maxRegret {
					maxRegret = effectiveScore
					chosen = k
				}
			}
			if maxRegret == -INF_COST {
				minDelta := INF_COST
				for k, c := range candidates {
					if c.delta < minDelta {
						minDelta = c.delta
						chosen = k
					}
				}
			}
			bc := candidates[chosen]
			target := &dispatch.Assigns[bc.idx]
			if target.AddShip(orderID, oriSt, desSt) {
				target.GenRoute()
				if target.Cost >= 0 {
					inserted = true
				} else {
					target.RemoveShip(orderID)
					target.GenRoute()
				}
			}
		}
		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					fallbackIdx = i
					break
				}
				if dispatch.Assigns[i].StationCurrent.X == 0 && dispatch.Assigns[i].StationCurrent.Y == 0 && dispatch.Assigns[i].StationsLen == 0 {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS {
				cand := &dispatch.Assigns[fallbackIdx]
				if cand.AddShip(orderID, oriSt, desSt) {
					cand.GenRoute()
					if cand.Cost >= 0 {
						if fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = fallbackIdx + 1
						}
						inserted = true
					} else {
						cand.RemoveShip(orderID)
						cand.GenRoute()
					}
				}
			}
			if !inserted {
				for i := 0; i < MAXASSIGNS; i++ {
					if i >= dispatch.AssignsLen {
						cand := &dispatch.Assigns[i]
						if cand.AddShip(orderID, oriSt, desSt) {
							cand.GenRoute()
							if cand.Cost >= 0 {
								dispatch.AssignsLen = i + 1
								inserted = true
								break
							} else {
								cand.RemoveShip(orderID)
								cand.GenRoute()
							}
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

