population.algorithm:
Greedy insertion with parallel cost evaluation across all feasible positions per route, using a normalized composite score of marginal distance, time-window urgency, and load balancing, with deterministic fallback to first empty or new assign slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for k := 0; k < orderCount; k++ {
		oriSt := oris[k]
		desSt := dess[k]
		orderID := total_ship + k
		orderLoad := oriSt.Load + desSt.Load
		type candidate struct {
			idx   int
			score float64
			pos   int
		}
		var bestCandidate candidate
		bestCandidate.score = INF_COST
		savedCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			asgn := &dispatch.Assigns[i]
			if asgn.AddShip(orderID, oriSt, desSt) {
				asgn.GenRoute()
				delta := asgn.Cost - savedCosts[i]
				if asgn.Cost >= 0 {
					timeUrgency := 0.0
					if oriSt.TimeEnd > 0 || desSt.TimeEnd > 0 {
						tsOri := 0.0
						tsDes := 0.0
						if oriSt.TimeEnd > 0 {
							tsOri = float64(oriSt.TimeEnd)
						}
						if desSt.TimeEnd > 0 {
							tsDes = float64(desSt.TimeEnd)
						}
						timeUrgency = 1.0 / (tsOri + tsDes + 1.0)
					}
					loadFactor := 1.0 + float64(orderLoad)*0.005
					baseDist := cal_dis(asgn.StationCurrent, oriSt) + cal_dis(oriSt, desSt)
					normDist := baseDist / (cal_dis(oriSt, desSt) + 1.0)
					composite := delta*loadFactor + normDist*5.0 + timeUrgency*500.0
					if composite < bestCandidate.score {
						bestCandidate.idx = i
						bestCandidate.score = composite
						bestCandidate.pos = -1
					}
				}
				asgn.RemoveShip(orderID)
				asgn.GenRoute()
			}
		}
		inserted := false
		if bestCandidate.idx >= 0 {
			tgt := &dispatch.Assigns[bestCandidate.idx]
			if tgt.AddShip(orderID, oriSt, desSt) {
				tgt.GenRoute()
				if tgt.Cost >= 0 {
